query:
SELECT COUNT(*) as total_certs FROM certificacoes;
SELECT COUNT(*) as com_match FROM certificacoes c JOIN agentes a ON UPPER(c.chaveJ) = UPPER(a.chaveJ);
SELECT c.chaveJ, a.chaveJ as agente_chaveJ, a.nomeAgente, a.empresa FROM certificacoes c LEFT JOIN agentes a ON UPPER(c.chaveJ) = UPPER(a.chaveJ) LIMIT 5;

